const now = Date.now();
const windowEnd = now + (16 * 60 * 60 * 1000); // next 16 hours

const calEvents = flow.get('caroline_calendar') || global.get('caroline_calendar') || [];
if (!calEvents.length) {
  node.warn('AutoTask: no calendar events in context');
  return null;
}

// Track which event keys we've already auto-tasked
const seen = flow.get('autotask_seen') || {};

// Expire seen entries older than 2 days
const twoDaysAgo = now - (2 * 24 * 60 * 60 * 1000);
Object.keys(seen).forEach(k => { if (seen[k] < twoDaysAgo) delete seen[k]; });

const newEvents = calEvents.filter(e => {
  const start = new Date(e.start || e.time || '');
  if (isNaN(start.getTime())) return false;
  const ts = start.getTime();
  if (ts < now || ts > windowEnd) return false;
  const key = (e.summary || e.title || 'Untitled') + '|' + (e.start || e.time || '');
  return !seen[key];
});

if (!newEvents.length) {
  node.warn('AutoTask: no new upcoming events to task');
  return null;
}

msg = { newEvents, seen };
return msg;

const events = msg.newEvents || [];
const seen = msg.seen || {};
const tasks = [];

events.forEach(e => {
  const title = e.summary || e.title || 'Untitled Event';
  const start = new Date(e.start || e.time || '');
  const timeStr = start.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
  const key = title + '|' + (e.start || e.time || '');

  tasks.push({ text: 'Prep for: ' + title + ' @ ' + timeStr, tag: 'auto', createdAt: Date.now() });
  seen[key] = Date.now();
});

flow.set('autotask_seen', seen);

if (!tasks.length) return null;

msg = { payload: JSON.stringify({ type: 'todo_update', action: 'add', tasks }) };
return msg;
